import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Explanation {
  testName: string;
  whatItIs: string;
  whatItMeasures: string;
  whyItsOrdered: string;
  analogy: string;
  educationalNotes: string;
}

export interface ExplanationResponse {
  explanations: Explanation[];
}

export enum AppState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { ExplanationResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are a friendly, simple, anxiety-reducing medical explainer. 
Your goal is to help users understand medical jargon and blood test terms in clear, everyday language.

STRICT RULES:
1. Explain WHAT terms mean, WHAT they measure, and WHY they are ordered.
2. DO NOT diagnose any condition or suggest a user has a disease.
3. DO NOT interpret personal lab results. If the user provides a number (e.g. "ALT 50"), IGNORE the number "50". Explain only what ALT is.
4. DO NOT say "Your value is high" or "This could mean you have X".
5. Use a friendly, calm, reassuring tone. No fear-inducing language.
6. Use simple, everyday words. Avoid jargon unless explaining it.
7. Use analogies to make things clear.

For each test found in the input, provide:
- testName: The name/acronym of the test.
- whatItIs: A simple definition.
- whatItMeasures: What specific substance or activity is tracked.
- whyItsOrdered: Common reasons a doctor might want this information.
- analogy: A simple real-world visual analogy.
- educationalNotes: General educational context.

Output MUST be a JSON object containing an "explanations" array.
`;

export const getMedicalExplanations = async (input: string | { data: string, mimeType: string }): Promise<ExplanationResponse> => {
  const model = ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: typeof input === 'string' 
      ? [{ parts: [{ text: input }] }]
      : { parts: [
          { inlineData: { data: input.data, mimeType: input.mimeType } },
          { text: "Extract and explain all medical test names found in this report." }
        ]},
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          explanations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                testName: { type: Type.STRING },
                whatItIs: { type: Type.STRING },
                whatItMeasures: { type: Type.STRING },
                whyItsOrdered: { type: Type.STRING },
                analogy: { type: Type.STRING },
                educationalNotes: { type: Type.STRING },
              },
              required: ["testName", "whatItIs", "whatItMeasures", "whyItsOrdered", "analogy", "educationalNotes"]
            }
          }
        },
        required: ["explanations"]
      }
    }
  });

  const response = await model;
  const text = response.text || '{"explanations":[]}';
  return JSON.parse(text) as ExplanationResponse;
};

import React from 'react';

const Header: React.FC = () => {
  return (
    <header className="py-12 text-center">
      <div className="inline-flex items-center justify-center p-3 mb-6 rounded-full bg-blue-100 text-blue-600">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
        </svg>
      </div>
      <h1 className="text-4xl font-bold text-gray-900 mb-4">Medly Explainer</h1>
      <p className="text-lg text-gray-600 max-w-2xl mx-auto px-4 leading-relaxed">
