export default Header;

import React, { useState, useRef } from 'react';

interface InputSectionProps {
  onProcessText: (text: string) => void;
  onProcessFile: (base64: string, mimeType: string) => void;
  isLoading: boolean;
}

const InputSection: React.FC<InputSectionProps> = ({ onProcessText, onProcessFile, isLoading }) => {
  const [text, setText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (text.trim()) {
      onProcessText(text);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = (reader.result as string).split(',')[1];
        onProcessFile(base64, file.type);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-8 mb-8 max-w-3xl mx-auto">
      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label htmlFor="jargon" className="block text-sm font-semibold text-gray-700 mb-2">
            Ask about a test or term
          </label>
          <div className="relative">
            <input
              id="jargon"
              type="text"
              value={text}
              onChange={(e) => setText(e.target.value)}
              placeholder="e.g., What is ALT? or HDL Cholesterol..."
              className="w-full px-5 py-4 rounded-2xl bg-gray-50 border border-gray-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all text-gray-900 placeholder-gray-400"
              disabled={isLoading}
            />
            <button
              type="submit"
              disabled={isLoading || !text.trim()}
              className="absolute right-2 top-2 bottom-2 px-6 rounded-xl bg-blue-600 text-white font-medium hover:bg-blue-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
            >
              {isLoading ? 'Thinking...' : 'Explain'}
            </button>
          </div>
        </div>

        <div className="relative">
          <div className="absolute inset-0 flex items-center" aria-hidden="true">
            <div className="w-full border-t border-gray-200"></div>
          </div>
          <div className="relative flex justify-center text-sm">
            <span className="px-4 bg-white text-gray-400 font-medium italic">or upload a report</span>
          </div>
        </div>

        <div 
          onClick={() => !isLoading && fileInputRef.current?.click()}
          className={`group flex flex-col items-center justify-center border-2 border-dashed border-gray-200 rounded-2xl p-8 cursor-pointer transition-all hover:border-blue-400 hover:bg-blue-50/30 ${isLoading ? 'opacity-50 cursor-not-allowed' : ''}`}
        >
          <div className="p-3 bg-blue-50 rounded-full text-blue-500 mb-3 group-hover:scale-110 transition-transform">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
            </svg>
          </div>
          <p className="text-sm font-medium text-gray-700">Click to upload image or PDF</p>
          <p className="text-xs text-gray-400 mt-1 text-center">We'll find the test names and explain them one by one.</p>
          <input 
            type="file" 
            className="hidden" 
            ref={fileInputRef} 
            accept="image/*,application/pdf"
            onChange={handleFileChange}
            disabled={isLoading}
          />
        </div>
      </form>
    </div>
  );
};

export default InputSection;

import React from 'react';

const SafetyFooter: React.FC = () => {
  return (
    <footer className="mt-20 border-t border-gray-200 py-12 px-6">
      <div className="max-w-3xl mx-auto text-center">
        <div className="inline-block p-4 bg-orange-50 border border-orange-100 rounded-2xl mb-6">
          <p className="text-orange-800 text-sm font-medium">
            🛡️ Safety Reminder: This explanation is for educational purposes only and is not a diagnosis or medical advice.
          </p>
        </div>
        <p className="text-gray-400 text-xs leading-relaxed">
          Medly Explainer uses AI to process information. AI can occasionally make mistakes or miss context. Always review health information with a qualified provider. We do not store your personal lab values.
        </p>
