export default SafetyFooter;

import React, { useState } from 'react';
import Header from './components/Header';
import InputSection from './components/InputSection';
import ExplanationCard from './components/ExplanationCard';
import SafetyFooter from './components/SafetyFooter';
import { getMedicalExplanations } from './services/geminiService';
import { AppState, Explanation } from './types';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.IDLE);
  const [explanations, setExplanations] = useState<Explanation[]>([]);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const processText = async (text: string) => {
    try {
      setState(AppState.LOADING);
      setErrorMessage(null);
      const result = await getMedicalExplanations(text);
      setExplanations(result.explanations);
      setState(AppState.SUCCESS);
    } catch (error) {
      console.error(error);
      setErrorMessage('Oops! We had some trouble understanding that. Please try again with a clearer term.');
      setState(AppState.ERROR);
    }
  };

  const processFile = async (base64: string, mimeType: string) => {
    try {
      setState(AppState.LOADING);
      setErrorMessage(null);
      const result = await getMedicalExplanations({ data: base64, mimeType });
      setExplanations(result.explanations);
      setState(AppState.SUCCESS);
    } catch (error) {
      console.error(error);
      setErrorMessage('We couldn\'t read that report. Make sure it\'s a clear photo of a lab result.');
      setState(AppState.ERROR);
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <main className="flex-grow container mx-auto px-4 max-w-5xl">
        <Header />

        <InputSection 
          onProcessText={processText} 
          onProcessFile={processFile}
          isLoading={state === AppState.LOADING}
        />

        {state === AppState.LOADING && (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-500 font-medium animate-pulse">Simplifying your results...</p>
          </div>
        )}

        {state === AppState.ERROR && errorMessage && (
          <div className="bg-red-50 border border-red-100 rounded-2xl p-6 text-center mb-8">
            <p className="text-red-700 font-medium">{errorMessage}</p>
            <button 
              onClick={() => setState(AppState.IDLE)}
              className="mt-4 text-sm font-bold text-red-600 hover:underline"
            >
              Try another search
            </button>
          </div>
        )}

        {state === AppState.SUCCESS && explanations.length > 0 && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-12 mb-20">
            {explanations.map((exp, index) => (
              <ExplanationCard key={`${exp.testName}-${index}`} explanation={exp} />
            ))}
          </div>
        )}

        {state === AppState.SUCCESS && explanations.length === 0 && (
          <div className="bg-gray-50 rounded-2xl p-12 text-center text-gray-500">
            <p>No medical tests were found in that request. Try typing a specific term like "ALT" or "Creatinine".</p>
          </div>
        )}

        {state === AppState.IDLE && (
          <div className="mt-20 grid grid-cols-1 md:grid-cols-3 gap-6 opacity-60">
            <div className="text-center p-6">
              <div className="text-2xl mb-2">🌬️</div>
              <h4 className="font-bold text-gray-700 mb-1">Stay Calm</h4>
              <p className="text-sm text-gray-500">We keep it simple and reassuring.</p>
            </div>
            <div className="text-center p-6">
              <div className="text-2xl mb-2">📖</div>
              <h4 className="font-bold text-gray-700 mb-1">Clear English</h4>
              <p className="text-sm text-gray-500">No dense medical jargon here.</p>
            </div>
            <div className="text-center p-6">
              <div className="text-2xl mb-2">🤝</div>
              <h4 className="font-bold text-gray-700 mb-1">Educational</h4>
              <p className="text-sm text-gray-500">Built to help you learn, not worry.</p>
            </div>
          </div>
        )}
      </main>

      <SafetyFooter />
    </div>
  );
};

export default App;

export interface Explanation {
  testName: string;
  value?: string | number;
  unit?: string;
  refMin?: number;
  refMax?: number;
  interpretation?: 'LOW' | 'NORMAL' | 'HIGH' | 'NOT_APPLICABLE';
  whatItIs: string;
  whatItMeasures: string;
  whyItsOrdered: string;
  upReasons: string;
  downReasons: string;
  analogy: string;
  educationalNotes: string;
  personalInsight: string;
  doctorAdvice: string;
}

export interface ExplanationResponse {
  explanations: Explanation[];
}

export enum AppState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { ExplanationResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are a friendly, expert medical explainer. 
Your goal is to help users understand their blood test results in clear, everyday language.

NEW MISSION:
1. Extract test names, user values, units, and reference ranges (min/max) from the provided text or image.
2. Interpret the value: Determine if it is LOW, NORMAL, or HIGH based on the reference range provided.
3. Explain why levels go UP and why they go DOWN for each specific test.
4. Provide a "Personal Insight": This should be a friendly sentence linking their specific value to common health concepts (e.g., "Your Ferritin is slightly low - this is often linked to iron intake.").
5. Provide "Doctor Advice": Clear, non-alarmist criteria for when the user should prioritize talking to a physician.
6. Still include the basic "What it is" and "Analogy" components.

TONE: Friendly, expert, calm.
STRICT RULE: Include the disclaimer in every response. Always emphasize that this is educational context, not a diagnosis.
`;

export const getMedicalExplanations = async (input: string | { data: string, mimeType: string }): Promise<ExplanationResponse> => {
  const model = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: typeof input === 'string' 
      ? [{ parts: [{ text: input }] }]
      : { parts: [
          { inlineData: { data: input.data, mimeType: input.mimeType } },
          { text: "Extract all tests. For each, include the value, unit, and reference range found. If multiple historical values exist, focus on the most recent but mention the trend in personalInsight." }
        ]},
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          explanations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                testName: { type: Type.STRING },
                value: { type: Type.STRING },
                unit: { type: Type.STRING },
                refMin: { type: Type.NUMBER },
                refMax: { type: Type.NUMBER },
                interpretation: { 
                  type: Type.STRING, 
                  description: "Must be LOW, NORMAL, HIGH, or NOT_APPLICABLE" 
                },
                whatItIs: { type: Type.STRING },
                whatItMeasures: { type: Type.STRING },
                whyItsOrdered: { type: Type.STRING },
                upReasons: { type: Type.STRING },
                downReasons: { type: Type.STRING },
                analogy: { type: Type.STRING },
                educationalNotes: { type: Type.STRING },
                personalInsight: { type: Type.STRING },
                doctorAdvice: { type: Type.STRING },
              },
              required: [
                "testName", "whatItIs", "upReasons", "downReasons", 
                "analogy", "personalInsight", "doctorAdvice"
              ]
            }
          }
        },
        required: ["explanations"]
      }
    }
  });

  const text = model.text || '{"explanations":[]}';
  return JSON.parse(text) as ExplanationResponse;
};

import React from 'react';

interface ResultMeterProps {
  value: number;
  min: number;
  max: number;
  unit: string;
}

const ResultMeter: React.FC<ResultMeterProps> = ({ value, min, max, unit }) => {
  // Calculate relative position (0 to 100)
  // We extend the range slightly on both ends for visual context
  const range = max - min;
  const padding = range * 0.5;
  const start = min - padding;
  const end = max + padding;

  const percentage = Math.max(0, Math.min(100, ((value - start) / (end - start)) * 100));

  const minPos = ((min - start) / (end - start)) * 100;
  const maxPos = ((max - start) / (end - start)) * 100;

  return (
    <div className="mt-4 mb-8">
      <div className="flex justify-between items-end mb-2">
        <span className="text-2xl font-bold text-gray-900">{value} <span className="text-sm font-medium text-gray-400">{unit}</span></span>
        <div className="text-right">
          <span className="text-xs font-bold text-gray-400 uppercase">Ref Range</span>
          <div className="text-sm text-gray-600 font-medium">{min} - {max}</div>
        </div>
      </div>

      <div className="relative h-4 w-full bg-gray-100 rounded-full overflow-hidden">
        {/* Low Zone (Yellow-ish) */}
        <div className="absolute inset-y-0 left-0 bg-amber-200" style={{ width: `${minPos}%` }}></div>
        {/* Normal Zone (Green) */}
        <div className="absolute inset-y-0 bg-emerald-400" style={{ left: `${minPos}%`, width: `${maxPos - minPos}%` }}></div>
        {/* High Zone (Red-ish) */}
        <div className="absolute inset-y-0 right-0 bg-rose-200" style={{ left: `${maxPos}%` }}></div>

        {/* Value Pointer */}
        <div 
          className="absolute top-0 bottom-0 w-1 bg-gray-900 border-x border-white shadow-sm transition-all duration-1000 ease-out"
          style={{ left: `${percentage}%` }}
        ></div>
      </div>

      <div className="flex justify-between mt-1 px-1">
        <span className="text-[10px] font-bold text-amber-600 uppercase">Low</span>
        <span className="text-[10px] font-bold text-emerald-600 uppercase">Normal</span>
        <span className="text-[10px] font-bold text-rose-600 uppercase">High</span>
      </div>
    </div>
  );
};

export default ResultMeter;

import React from 'react';
import { Explanation } from '../types';
import ResultMeter from './ResultMeter';

interface ExplanationCardProps {
  explanation: Explanation;
}

const ExplanationCard: React.FC<ExplanationCardProps> = ({ explanation }) => {
  const valNum = typeof explanation.value === 'string' ? parseFloat(explanation.value) : explanation.value;
  const hasRange = typeof valNum === 'number' && explanation.refMin !== undefined && explanation.refMax !== undefined;

  const getStatusColor = () => {
    switch (explanation.interpretation) {
      case 'LOW': return 'bg-amber-100 text-amber-700 border-amber-200';
      case 'HIGH': return 'bg-rose-100 text-rose-700 border-rose-200';
      case 'NORMAL': return 'bg-emerald-100 text-emerald-700 border-emerald-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-md border border-gray-100 overflow-hidden flex flex-col h-full animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-50 p-6 flex items-start justify-between border-b border-gray-100">
        <div>
          <h3 className="text-2xl font-bold text-gray-900 leading-tight">{explanation.testName}</h3>
          <p className="text-sm text-gray-500 mt-1">{explanation.whatItMeasures}</p>
        </div>
        {explanation.interpretation && explanation.interpretation !== 'NOT_APPLICABLE' && (
          <span className={`px-4 py-1 rounded-full text-xs font-black uppercase tracking-widest border ${getStatusColor()}`}>
            {explanation.interpretation}
          </span>
        )}
      </div>

      <div className="p-8 space-y-8 flex-grow">
        {hasRange && (
          <ResultMeter 
            value={valNum!} 
            min={explanation.refMin!} 
            max={explanation.refMax!} 
            unit={explanation.unit || ''} 
          />
        )}

        <div className="bg-blue-50/50 rounded-2xl p-5 border border-blue-100">
          <h4 className="flex items-center text-blue-800 font-bold mb-2">
            <span className="mr-2">✨</span> Personal Insight
          </h4>
          <p className="text-blue-900 leading-relaxed text-sm">{explanation.personalInsight}</p>
        </div>

        <section>
          <h4 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-3">Understanding the Level</h4>
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-rose-50/30 p-4 rounded-xl border border-rose-100/50">
              <div className="flex items-center text-rose-600 font-bold text-xs mb-2">
                <svg className="w-3 h-3 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 10l7-7m0 0l7 7m-7-7v18" /></svg>
                WHY IT GOES UP
              </div>
              <p className="text-xs text-gray-600 leading-relaxed">{explanation.upReasons}</p>
            </div>
            <div className="bg-amber-50/30 p-4 rounded-xl border border-amber-100/50">
              <div className="flex items-center text-amber-600 font-bold text-xs mb-2">
                <svg className="w-3 h-3 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 14l-7 7m0 0l-7-7m7 7V3" /></svg>
                WHY IT GOES DOWN
              </div>
              <p className="text-xs text-gray-600 leading-relaxed">{explanation.downReasons}</p>
            </div>
          </div>
        </section>

        <section>
          <h4 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-2">The Big Picture</h4>
          <p className="text-gray-700 text-sm leading-relaxed">{explanation.whatItIs}</p>
        </section>

        <section className="bg-gray-50 rounded-xl p-4 italic">
          <p className="text-gray-600 text-sm">
            <span className="font-bold text-gray-800 not-italic mr-1">Analogy:</span>
            {explanation.analogy}
          </p>
        </section>

        <div className="bg-indigo-900 text-white rounded-2xl p-5 shadow-inner">
          <h4 className="text-xs font-black uppercase tracking-widest text-indigo-300 mb-2">When to talk to a doctor</h4>
          <p className="text-sm leading-relaxed opacity-90">{explanation.doctorAdvice}</p>
        </div>
      </div>

      <div className="px-8 py-4 bg-gray-50 text-[10px] text-gray-400 italic text-center border-t border-gray-100">
        This insight is for educational context and does not replace medical consultation.
      </div>
    </div>
  );
};

export default ExplanationCard;

import React, { useState } from 'react';
import Header from './components/Header';
import InputSection from './components/InputSection';
import ExplanationCard from './components/ExplanationCard';
import SafetyFooter from './components/SafetyFooter';
import { getMedicalExplanations } from './services/geminiService';
import { AppState, Explanation } from './types';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.IDLE);
  const [explanations, setExplanations] = useState<Explanation[]>([]);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const processText = async (text: string) => {
    try {
      setState(AppState.LOADING);
      setErrorMessage(null);
      const result = await getMedicalExplanations(text);
      setExplanations(result.explanations);
      setState(AppState.SUCCESS);
    } catch (error) {
      console.error(error);
      setErrorMessage('Oops! We had some trouble understanding that. Please try again with a clearer term.');
      setState(AppState.ERROR);
    }
  };

  const processFile = async (base64: string, mimeType: string) => {
    try {
      setState(AppState.LOADING);
      setErrorMessage(null);
      const result = await getMedicalExplanations({ data: base64, mimeType });
      setExplanations(result.explanations);
      setState(AppState.SUCCESS);
    } catch (error) {
      console.error(error);
      setErrorMessage('We couldn\'t read that report. Make sure it\'s a clear photo of a lab result.');
      setState(AppState.ERROR);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <main className="flex-grow container mx-auto px-4 max-w-6xl">
        <Header />

        <InputSection 
          onProcessText={processText} 
          onProcessFile={processFile}
          isLoading={state === AppState.LOADING}
        />

        {state === AppState.LOADING && (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="relative">
              <div className="w-16 h-16 border-4 border-blue-100 rounded-full"></div>
              <div className="absolute top-0 w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
            </div>
            <div className="text-center">
              <p className="text-blue-900 font-bold text-lg animate-pulse">Analyzing results...</p>
              <p className="text-gray-400 text-sm mt-1">Extracting values and interpreting ranges</p>
            </div>
          </div>
        )}

        {state === AppState.ERROR && errorMessage && (
          <div className="bg-red-50 border border-red-100 rounded-3xl p-8 text-center mb-8 max-w-2xl mx-auto shadow-sm">
            <div className="text-3xl mb-4">⚠️</div>
            <p className="text-red-700 font-bold text-lg mb-2">Something went wrong</p>
            <p className="text-red-600 mb-6">{errorMessage}</p>
            <button 
              onClick={() => setState(AppState.IDLE)}
              className="px-8 py-3 bg-red-600 text-white rounded-2xl font-bold hover:bg-red-700 transition-colors shadow-lg shadow-red-200"
            >
              Try another search
            </button>
          </div>
        )}

        {state === AppState.SUCCESS && explanations.length > 0 && (
          <div className="mt-12 mb-20">
            <div className="flex items-center justify-between mb-8 px-4">
              <h2 className="text-2xl font-bold text-gray-900">Your Explanations</h2>
