interface InputSectionProps {
  onProcessText: (text: string) => void;
  onProcessFile: (base64: string, mimeType: string) => void;
  isLoading: boolean;
}

const InputSection: React.FC<InputSectionProps> = ({ onProcessText, onProcessFile, isLoading }) => {
  const [text, setText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (text.trim()) {
      onProcessText(text);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = (reader.result as string).split(',')[1];
        onProcessFile(base64, file.type);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="max-w-4xl mx-auto mb-12">
      <div className="bg-white rounded-[40px] shadow-xl shadow-blue-900/5 p-2 transition-all border border-white">
