import React from 'react';

interface ResultMeterProps {
  value: number;
  min: number;
  max: number;
  unit: string;
}

const ResultMeter: React.FC<ResultMeterProps> = ({ value, min, max, unit }) => {
  const range = max - min;
  const padding = range * 0.4;
  const start = min - padding;
  const end = max + padding;

  const percentage = Math.max(0, Math.min(100, ((value - start) / (end - start)) * 100));

  const minPos = ((min - start) / (end - start)) * 100;
  const maxPos = ((max - start) / (end - start)) * 100;

  return (
    <div className="animate-in fade-in slide-in-from-left-4 duration-1000">
      <div className="flex justify-between items-baseline mb-4">
        <div>
          <span className="text-4xl font-extrabold text-[#1B2A41]">{value}</span>
          <span className="text-sm font-bold text-slate-400 ml-2 uppercase tracking-widest">{unit}</span>
        </div>
        <div className="text-right">
          <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest block mb-0.5">Reference Range</span>
          <div className="text-sm text-[#1B2A41] font-bold bg-white px-2 py-0.5 rounded-lg border border-slate-100 shadow-sm">
            {min} – {max}
          </div>
        </div>
      </div>

      <div className="relative h-3 w-full bg-slate-200/50 rounded-full overflow-visible">
        {/* Background segments */}
        <div className="absolute inset-y-0 left-0 bg-amber-200/40 rounded-l-full" style={{ width: `${minPos}%` }}></div>
        <div className="absolute inset-y-0 bg-teal-400/40" style={{ left: `${minPos}%`, width: `${maxPos - minPos}%` }}></div>
        <div className="absolute inset-y-0 right-0 bg-rose-200/40 rounded-r-full" style={{ left: `${maxPos}%` }}></div>

        {/* Value Marker */}
        <div 
          className="absolute -top-1 w-2 h-5 bg-[#1B2A41] border-2 border-white rounded-full shadow-md z-10 transition-all duration-1000 cubic-bezier(0.34, 1.56, 0.64, 1)"
          style={{ left: `calc(${percentage}% - 4px)` }}
        >
          <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 bg-[#1B2A41] text-white text-[8px] px-1.5 py-0.5 rounded-md font-black uppercase tracking-widest">YOU</div>
        </div>
      </div>

      <div className="flex justify-between mt-4 px-1">
        <div className="flex items-center gap-1.5">
          <span className="w-1.5 h-1.5 rounded-full bg-amber-300"></span>
          <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Lower</span>
        </div>
        <div className="flex items-center gap-1.5">
          <span className="w-1.5 h-1.5 rounded-full bg-teal-400"></span>
          <span className="text-[9px] font-black text-teal-600 uppercase tracking-[0.2em]">Normal</span>
        </div>
        <div className="flex items-center gap-1.5">
          <span className="w-1.5 h-1.5 rounded-full bg-rose-300"></span>
          <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Higher</span>
        </div>
      </div>
    </div>
  );
};

export default ResultMeter;

